import sys

def fast_power(base: int, exponent: int) -> int:
    result = 1
    while exponent:
        if exponent & 1:
            result *= base
        base *= base
        exponent >>= 1
    return result

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        base = int(next(it))
        exponent = int(next(it))
        out.append(str(fast_power(base, exponent)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

